const staticData = $getStaticData();
if (!staticData.recentModels) staticData.recentModels = [];

const allModels = ["Deepika Style", "Priyanka Style", "Alia Style", "Katrina Style", "Kareena Style"];
const recentModelsList = staticData.recentModels.flat();
let availableModels = allModels.filter(m => !recentModelsList.includes(m));

if (availableModels.length < 2) {
  staticData.recentModels = [];
  availableModels = [...allModels];
}

let shuffled = availableModels.sort(() => 0.5 - Math.random());
const selectedModels = shuffled.slice(0, 2);

staticData.recentModels.push(selectedModels);
if (staticData.recentModels.length > 5) staticData.recentModels.shift();

return [{
  json: {
    selectedModels
  }
}];

