const item = $input.item;
// Parse the JSON string from Gemini
const textResponse = item.json.candidates[0].content.parts[0].text;
item.json.prompts = JSON.parse(textResponse);
return item;

// Extract message data from Telegram update
const update = $input.first().json;
const message = update.message || update.edited_message;

if (!message) {
  return [{ json: { skip: true, reason: 'No message found' } }];
}

const text = (message.text || '').trim();
const chatId = message.chat.id;
const userId = message.from.id;
const username = message.from.username || message.from.first_name || 'Unknown';
const messageId = message.message_id;
const timestamp = new Date(message.date * 1000).toISOString();
const date = timestamp.split('T')[0];

// Detect message type
let messageType = 'unknown';

if (text.startsWith('/')) {
  messageType = 'command';
} else if (text.startsWith('#')) {
  messageType = 'update';
} else {
  messageType = 'natural_language';
}

return [{
  json: {
    text,
    chatId: String(chatId),
    userId: String(userId),
    username,
    messageId,
    timestamp,
    date,
    messageType
  }
}];

// Parse structured update: #department Task | status | notes
const item = $input.first().json;
const text = item.text;

// Valid departments and statuses
const DEPARTMENTS = ['marketing', 'design', 'dev', 'sales'];
const DEPT_LABELS = {
  marketing: 'Marketing',
  design: 'Design',
  dev: 'Development',
  sales: 'Sales'
};
const STATUSES = ['in_progress', 'ready_for_review', 'completed', 'blocked'];
const STATUS_LABELS = {
  in_progress: 'In Progress',
  ready_for_review: 'Ready for Review',
  completed: 'Completed',
  blocked: 'Blocked'
};

// Pattern: #dept Task | status | notes (notes optional)
const pattern = /^#(\\w+)\\s+([^|]+)\\|\\s*([^|]+)(?:\\|\\s*(.+))?$/i;
const match = text.match(pattern);

if (!match) {
  return [{
    json: {
      ...item,
      parseError: true,
      errorMessage: [
        '❌ *Format not recognised.*',
        '',
        'Please use:',
        '`#department Task description | status | notes`',
        '',
        '*Departments:* #marketing #design #dev #sales',
        '*Statuses:* in_progress | ready_for_review | completed | blocked',
        '',
        '*Example:*',
        '`#marketing Banner ad designed | ready_for_review | Needs sign-off`'
      ].join('\\n')
    }
  }];
}

const rawDept = match[1].toLowerCase();
const task = match[2].trim();
const rawStatus = match[3].trim().toLowerCase().replace(/\\s+/g, '_');
const notes = (match[4] || '').trim();

if (!DEPARTMENTS.includes(rawDept)) {
  return [{
    json: {
      ...item,
      parseError: true,
      errorMessage: `❌ Unknown department *#${rawDept}*\\n\\nValid departments: ${DEPARTMENTS.map(d => '#' + d).join(', ')}`
    }
  }];
}

if (!STATUSES.includes(rawStatus)) {
  return [{
    json: {
      ...item,
      parseError: true,
      errorMessage: `❌ Unknown status *${rawStatus}*\\n\\nValid statuses:\\n${STATUSES.map(s => '• ' + s).join('\\n')}`
    }
  }];
}

return [{
  json: {
    ...item,
    parseError: false,
    department: rawDept,
    departmentLabel: DEPT_LABELS[rawDept],
    task,
    status: rawStatus,
    statusLabel: STATUS_LABELS[rawStatus],
    notes
  }
}];

